24	export const DebugBreakpoints = () => {
25	    const theme = useMantineTheme();
26	
27	    // Zero-size marker so we can observe the width of whatever DOM parent
28	    // this component is dropped into, i.e. the element a `@container` query
29	    // there would actually be measuring - not this component's own fixed box.
30	    const markerRef = useRef<HTMLSpanElement>(null);
31	    const [containerWidth, setContainerWidth] = useState(0);
32	
33	    useEffect(() => {
34	        const parent = markerRef.current?.parentElement;
35	        if (!parent) return;
36	
37	        const observer = new ResizeObserver(([entry]) => {
38	            setContainerWidth(entry.contentRect.width);
39	        });
40	        observer.observe(parent);
41	
42	        return () => observer.disconnect();
43	    }, []);
44	
45	    // Define media queries for each breakpoint
46	    const isXs = useMediaQuery(`(max-width: calc(${theme.breakpoints.sm} - 1px))`);
47	    const isSm = useMediaQuery(`(min-width: ${theme.breakpoints.sm}) and (max-width: calc(${theme.breakpoints.md} - 1px))`);
48	    const isMd = useMediaQuery(`(min-width: ${theme.breakpoints.md}) and (max-width: calc(${theme.breakpoints.lg} - 1px))`);
49	    const isLg = useMediaQuery(`(min-width: ${theme.breakpoints.lg}) and (max-width: calc(${theme.breakpoints.xl} - 1px))`);
50	    const isXl = useMediaQuery(`(min-width: ${theme.breakpoints.xl})`);
51	
52	    const viewportBreakpoint = useMemo(() => {
53	        if (isXs) return `XS (<${theme.breakpoints.sm})`;
54	        if (isSm) return `SM (${theme.breakpoints.sm})`;
55	        if (isMd) return `MD (${theme.breakpoints.md})`;
56	        if (isLg) return `LG (${theme.breakpoints.lg})`;
57	        if (isXl) return `XL+ (${theme.breakpoints.xl})`;
58	        return "Unknown";
59	    }, [isXs, isSm, isMd, isLg, isXl, theme.breakpoints]);
60	
61	    const containerBreakpoint = useMemo(
62	        () => bucketWidth(containerWidth, theme.breakpoints),
63	        [containerWidth, theme.breakpoints],
64	    );
65	
66	    useEffect(() => {
67	        // Pure side-effect (no setState) -> avoids cascading renders
68	        // eslint-disable-next-line no-console
69	        console.log(`Active Breakpoint — viewport: ${viewportBreakpoint}, container: ${containerBreakpoint}`);
70	    }, [viewportBreakpoint, containerBreakpoint]);
71	
72	    return (
73	        <>
74	            <Box component="span" ref={markerRef} style={{ display: 'none' }} />
75	            <Container className={classes.div}>
76	                <Text className={classes.p}>📏 <strong>Breakpoints</strong>: {JSON.stringify(theme.breakpoints)}</Text>
77	                <Text className={classes.p}>🖥️ <strong>Viewport</strong>: {viewportBreakpoint}</Text>
78	                <Text className={classes.p}>📦 <strong>Container ({Math.round(containerWidth)}px/{Math.round(containerWidth / PX_PER_EM)}em)</strong>: {containerBreakpoint}</Text>
79	            </Container>
80	        </>
81	    );
82	};
